// 1. Extraemos y parseamos los datos de Gemini
const rawText = $input.first().json.content.parts[0].text;
const data = JSON.parse(rawText);

// Nota: Ya no forzamos el signo negativo aquí. 
// Gemini se encarga de enviar -25000 si es gasto o 50 si es ingreso.
// Confiamos en el dato que viene en data.amount.

// 2. Construimos los parámetros de la URL
const queryString = Object.keys(data)
  .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(data[key])}`)
  .join('&');

// 3. Armamos el App Link oficial de Cashew
const deepLink = `https://cashewapp.web.app/addTransaction?${queryString}`;

// 4. Devolvemos los datos limpios al siguiente nodo
return {
  json: {
    deepLink: deepLink,
    transaccion: data 
  }
};

